//! A classification of known USB fingerprint sensors, generated from the libfprint driver
//! id-tables — do not edit by hand; regenerate with `cargo xtask device-db`.
//!
//! Each row is an interoperability fact: a `(vid, pid)` a libfprint driver claims, the
//! driver that claims it, and whether that driver produces a host-side image (so the
//! [`crate::FrameSource`] seam can reach it) or matches on the chip. `fpdev probe` reads
//! it to tell a user whether their sensor is reachable before they start on a driver.
//!
//! Rows are sorted by `(vid, pid)` and each pair appears once.

/// How a sensor's driver does matching, which decides whether a host-image seam can reach it.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Family {
    /// Streams pixels to the host; all matching runs here, so [`crate::FrameSource`] can drive it.
    HostImage,
    /// Enrolls and matches on the sensor; no image reaches the host.
    MatchOnChip,
    /// Neither archetype fits with confidence; not pinned to a seam.
    Other,
}

/// One known device: the USB ids it presents, the libfprint driver that claims it, and how
/// that driver matches.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct DeviceRecord {
    pub vid: u16,
    pub pid: u16,
    /// The libfprint driver id that claims this device.
    pub driver: &'static str,
    pub family: Family,
}

/// Every classified device, sorted by `(vid, pid)`; 256 rows, no duplicate keys.
