/// The record for a `(vid, pid)`, if one is known.
///
/// A binary search over [`DEVICES`], which is sorted by key.
#[must_use]
pub fn lookup(vid: u16, pid: u16) -> Option<&'static DeviceRecord> {
    DEVICES
        .binary_search_by(|r| (r.vid, r.pid).cmp(&(vid, pid)))
        .ok()
        .map(|i| &DEVICES[i])
}

/// The whole table.
#[must_use]
pub fn all() -> &'static [DeviceRecord] {
    DEVICES
}
